// Quick script to check xUnit v3 API using reflection
using System;
using System.Reflection;
using System.Linq;

var asm = Assembly.LoadFrom(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile) + "/.nuget/packages/xunit.v3.extensibility.core/3.2.2/lib/netstandard2.0/xunit.v3.core.dll");

// Find ITestCaseOrderer
var type = asm.GetTypes().FirstOrDefault(t => t.Name == "ITestCaseOrderer");
if (type != null) {
    Console.WriteLine($"Found: {type.FullName}");
    foreach (var m in type.GetMethods()) {
        Console.WriteLine($"  Method: {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))}) -> {m.ReturnType.Name}");
    }
}
else {
    Console.WriteLine("ITestCaseOrderer not found in extensibility.core");
    // Search for it
    foreach (var t in asm.GetTypes().Where(t => t.Name.Contains("Orderer"))) {
        Console.WriteLine($"  Found: {t.FullName}");
    }
}
CSHARP
